import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Category = 'All' | 'Shoes' | 'Sneakers' | 'Shirts' | 'Long Sleeves' | 'Bags';

export interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  category: Category;
  image: string;
}

export interface CartItem extends Product {
  quantity: number;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import { PRODUCTS } from "../constants";

const PRODUCT_CONTEXT = `
You are the AI Assistant for "Nicho's Importation", a premium e-commerce store.
Nicho imports high-quality shoes, shirts, footwear, sneakers, bags, and long sleeves.

Here is our current inventory:
${PRODUCTS.map(p => `- ${p.name}: $${p.price} (${p.category}) - ${p.description}`).join('\n')}

Rules:
1. Be polite and helpful.
2. If a user asks for a recommendation, suggest products from the inventory above.
3. If they ask about shipping, mention we offer fast international shipping.
4. Keep responses concise and focused on the products.
5. If someone asks for Nicho, mention he's the founder who personally curates every imported item.
`;

export class GeminiService {
  private ai: GoogleGenAI;
  private chat: Chat;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    this.chat = this.ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: PRODUCT_CONTEXT,
      },
    });
  }

  async sendMessage(message: string): Promise<string> {
    try {
      const response: GenerateContentResponse = await this.chat.sendMessage({ message });
      return response.text || "I'm sorry, I couldn't process that request.";
    } catch (error) {
      console.error("Gemini API Error:", error);
      return "Hello! I'm currently having a bit of trouble connecting, but feel free to browse our amazing imported collection!";
    }
  }
}

