import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import { PRODUCTS } from "../constants";

const PRODUCT_CONTEXT = `
You are the AI Assistant for "Nicho's Importation" in Ghana. 
Nicho imports premium quality footwear, sneakers, shirts, and bags.

Current Stock available for Ghana:
${PRODUCTS.map(p => `- ${p.name}: (${p.category}) - ${p.description}`).join('\n')}

Rules:
1. Speak like a friendly Ghanaian business assistant. Be very polite and helpful.
2. We use GH₵ (Ghana Cedis). However, prices are "Price on Request". 
3. If a user asks for prices, tell them to "Add to Order" and Nicho will give them the best current rate based on the market.
4. If they ask about delivery, tell them we deliver fast across Accra, Kumasi, and all over Ghana.
5. If they ask about the products, emphasize they are "High Grade" or "Grade 1" imports.
6. Nicho is the owner who hand-picks all the imports.
`;

export class GeminiService {
  private ai: GoogleGenAI;
  private chat: Chat;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    this.chat = this.ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: PRODUCT_CONTEXT,
      },
    });
  }

  async sendMessage(message: string): Promise<string> {
    try {
      const response: GenerateContentResponse = await this.chat.sendMessage({ message });
      return response.text || "I'm sorry, I couldn't process that. Please ask about our quality imports.";
    } catch (error) {
      console.error("Gemini API Error:", error);
      return "Hello! I'm having a small connection issue, but you can see all our latest quality imports right here on the page!";
    }
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { GeminiService } from '../services/geminiService';
import { ChatMessage } from '../types';

const AiAssistant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: "Hello! I'm Nicho's Assistant. Looking for the best quality imports in GH₵?" }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const geminiRef = useRef<GeminiService | null>(null);

  useEffect(() => {
    if (isOpen && !geminiRef.current) {
      geminiRef.current = new GeminiService();
    }
  }, [isOpen]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInput('');
    setIsLoading(true);

    if (geminiRef.current) {
      const response = await geminiRef.current.sendMessage(userMsg);
      setMessages(prev => [...prev, { role: 'model', text: response }]);
    }

    setIsLoading(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-[100]">
      {isOpen ? (
        <div className="bg-white w-80 sm:w-96 h-[500px] rounded-2xl shadow-2xl border border-gray-100 flex flex-col overflow-hidden animate-in slide-in-from-bottom-4 duration-300">
          <div className="bg-green-800 p-4 flex justify-between items-center text-white">
